function solve(points) {
    const n = points.length;
    if (n < 4) return 0;

    let count =   0;
    const lines = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const x1 = points[i][0], y1 = points[i][1];
            const x2 = points[j][0], y2 = points[j][1];
            let key;
            if (x1 === x2) {
                key = `inf_${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope}_${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key).push([i, j]);
        }
    }

    const lineGroups = Array.from(lines.values()).filter(group => group.length >= 2);

    for (const group of lineGroups) {
        const m = group.length;
        if (m < 2) continue;
        const pointSet = new Set();
        for (const [i, j] of group) {
            pointSet.add(i);
            pointSet.add(j);
        }
        const k = pointSet.size;
        if (k >= 4) {
            count += (k * (k - 1) * (k - 2) * (k - 3)) / 24;
        }
    }

    const totalCombinations = (n * (n - 1) * (n - 2) * (n - 3)) / 24;
    const parallelogramCount = countParallel(points);
    const rectangleCount = countRectangles(points);

    return count - 2 * parallelogramCount + rectangleCount;
}

function countParallel(points) {
    const n = points.length;
    const lines = new Map();

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const x1 = points[i][0], y1 = points[i][1];
            const x2 = points[j][0], y2 = points[j][1];
            let key;
            if (x1 === x2) {
                key = `inf_${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope}_${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key).push([i, j]);
        }
    }

    let count = 0;
    for (const group of lines.values()) {
        const m = group.length;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }
    return count;
}

function countRectangles(points) {
    const n = points.length;
